UPDATE public.service_library
SET academy_metadata = '{"displayName":"Ireland – Stamp 2 Student Permission","shortDescription":"Irish Immigration · Stamp 2 · IRP card · Approved course on ILEP","version":"v1.0","versionStatus":"Live","reviewStatus":"active","updatedLabel":"Updated 9 Jun 2026","learningLevel":"Intermediate","learningMinutes":20,"policyAlert":{"active":true,"date":"9 Jun 2026","summary":"Confirm visa fees and financial thresholds on irishimmigration.ie before quoting."},"alert":{"title":"IRP registration after arrival","body":"Students must register for Irish Residence Permit within 90 days of arrival. Verify current fee on irishimmigration.ie."},"tags":[{"label":"Active service","variant":"success"},{"label":"CAS required","variant":"warning"},{"label":"3–8 weeks","variant":"neutral"},{"label":"Online – Irish Immigration Service Delivery","variant":"neutral"}],"chips":[{"label":"3–8 weeks processing","variant":"neutral"},{"label":"€60+ (verify current fee) + IHS","variant":"neutral"},{"label":"CAS mandatory","variant":"success"},{"label":"Genuine student","variant":"warning"}],"kpis":[{"label":"Processing time","value":"3–8w","sub":"Outside Ireland standard","tone":"primary"},{"label":"Government fee","value":"€60+ (verify current fee)","sub":"+ IHS per year of course","tone":"warning"},{"label":"Our approval rate","value":"89%","sub":"~76% industry benchmark","tone":"success"},{"label":"Required docs","value":"13","sub":"+ financial evidence","tone":"violet"},{"label":"Consultancy fee","value":"See fee tab","sub":"+ govt & IHS","tone":"primary"}],"about":[{"label":"Description","value":"Student Route visa for study at a Ireland institution holding a valid sponsor licence. Requires Confirmation of Acceptance for Studies (CAS) and online Irish Immigration Service Delivery application."},{"label":"Eligible applicants","value":"Valid CAS · Proof of funds · English at required level · Genuine student intent · TB test if from listed country"},{"label":"Financial requirement","value":"Tuition minus deposit paid + living costs (London vs outside London rates). 28-day funds rule applies.","warning":true},{"label":"Key authority","value":"Ireland Visas and Immigration (Irish Immigration Service Delivery) — Home Office"},{"label":"After approval","value":"BRP or digital status; maintain attendance, sponsor reporting, and work hour limits."}],"eligibility":[{"criterion":"CAS from licensed Ireland sponsor","met":true,"note":"CAS number valid and unused"},{"criterion":"Financial requirement met (28-day rule)","met":true,"note":"Funds held 28 consecutive days"},{"criterion":"English language at SELT level (if required)","met":true,"note":"IELTS Irish Immigration Service Delivery or exempt pathway"},{"criterion":"TB test certificate (if applicable)","met":false,"note":"Required for Indian nationals"},{"criterion":"ATAS certificate (if course requires)","met":false,"note":"Check CAS and course code"},{"criterion":"Genuine student / credible study plan","met":true},{"criterion":"Immigration history disclosed","met":true}],"redFlagsBanner":"After refusal, analyse refusal letter and address specific grounds before reapplication with new CAS if needed.","redFlags":[{"title":"28-day funds rule breach","description":"Funds not held continuously for 28 days or balance drops below threshold.","fix":"Maintain required balance 28 days; use dated bank statements","severity":"Very common"},{"title":"CAS / course mismatch","description":"Course level inconsistent with prior study or career plan.","fix":"Align CAS course with academic progression; strong personal statement","severity":"Common"},{"title":"Wrong IHS payment","description":"Incorrect IHS amount or course duration entered.","fix":"Calculate IHS on irishimmigration.ie calculator before payment","severity":"Common"},{"title":"TB test issues","description":"Wrong clinic, expired certificate, or missing for India.","fix":"Use Irish Immigration Service Delivery-approved clinic; certificate valid 6 months","severity":"Common"},{"title":"Prior refusals not addressed","description":"Ireland or other refusals hidden in application.","fix":"Disclose and explain changed circumstances","severity":"High"},{"title":"Document quality","description":"Blurry scans, wrong translations, or inconsistent names.","fix":"Certified translations; consistent naming across docs","severity":"Medium"}],"faqs":[{"q":"Can we guarantee Student visa approval?","a":"No. Irish Immigration Service Delivery assesses each application. Strong CAS and funds help but approval is never guaranteed."},{"q":"How much funds for London vs outside London?","a":"Living costs differ—verify current amounts on irishimmigration.ie. Plus remaining tuition after deposit shown on CAS."},{"q":"What is the 28-day rule?","a":"Funds must remain at or above required amount for 28 consecutive days ending no more than 31 days before application."},{"q":"Can spouse join on Student visa?","a":"Dependants allowed only if course meets specific criteria (e.g., postgraduate level certain duration). Check current rules."},{"q":"Is IELTS Irish Immigration Service Delivery mandatory?","a":"If SELT required, must be Irish Immigration Service Delivery-approved test from approved centre. Some nationals/courses may be exempt."},{"q":"When to apply?","a":"Up to 6 months before course start if applying from outside Ireland. Do not apply without valid CAS."},{"q":"Can student work?","a":"Limited hours during term; rules on irishimmigration.ie. Cannot work as professional sportsperson or doctor in training."},{"q":"What after course completion?","a":"Discuss Graduate Route eligibility separately—requires successful completion at eligible institution."},{"q":"What is Description for this service?","a":"Student Route visa for study at a Ireland institution holding a valid sponsor licence. Requires Confirmation of Acceptance for Studies (CAS) and online Irish Immigration Service Delivery application."},{"q":"What is Eligible applicants for this service?","a":"Valid CAS · Proof of funds · English at required level · Genuine student intent · TB test if from listed country"},{"q":"What is Financial requirement for this service?","a":"Tuition minus deposit paid + living costs (London vs outside London rates). 28-day funds rule applies."},{"q":"Important note on Financial requirement?","a":"Tuition minus deposit paid + living costs (London vs outside London rates). 28-day funds rule applies."},{"q":"What is Key authority for this service?","a":"Ireland Visas and Immigration (Irish Immigration Service Delivery) — Home Office"},{"q":"What is After approval for this service?","a":"BRP or digital status; maintain attendance, sponsor reporting, and work hour limits."},{"q":"Is CAS from licensed Ireland sponsor required?","a":"CAS number valid and unused"},{"q":"Is Financial requirement met (28-day rule) required?","a":"Funds held 28 consecutive days"},{"q":"Is English language at SELT level (if required) required?","a":"IELTS Irish Immigration Service Delivery or exempt pathway"},{"q":"Is TB test certificate (if applicable) required?","a":"Required for Indian nationals"},{"q":"Is ATAS certificate (if course requires) required?","a":"Check CAS and course code"},{"q":"Is Genuine student / credible study plan required?","a":"Genuine student / credible study plan is typically required."},{"q":"Is Immigration history disclosed required?","a":"Immigration history disclosed is typically required."},{"q":"What is the Processing time?","a":"3–8w — Outside Ireland standard"},{"q":"What is the Government fee?","a":"€60+ (verify current fee) — + IHS per year of course"},{"q":"What is the Our approval rate?","a":"89% — ~76% industry benchmark"},{"q":"What is the Required docs?","a":"13 — + financial evidence"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & IHS"},{"q":"What if the client has 28-day funds rule breach?","a":"Maintain required balance 28 days; use dated bank statements"},{"q":"Why is 28-day funds rule breach a problem?","a":"Funds not held continuously for 28 days or balance drops below threshold."},{"q":"What if the client has CAS / course mismatch?","a":"Align CAS course with academic progression; strong personal statement"},{"q":"Why is CAS / course mismatch a problem?","a":"Course level inconsistent with prior study or career plan."}],"compliance":["Client service agreement and consent must be on file before submission","Never guarantee visa approval; use approved-language only in marketing","Fee quotes must separate consultancy, Irish Immigration Service Delivery fee, IHS, and third-party costs","TB test and SELT must be from Irish Immigration Service Delivery-approved providers only"],"proTips":["Verify sponsor licence on register before CAS fee","Calculate IHS with irishimmigration.ie calculator—save payment receipt","TB test at approved clinic early to avoid delays","28-day funds: set calendar reminder for client","Cross-check CAS details against passport before submit"],"postApproval":["Send visa vignette/BRP collection instructions","Remind sponsor reporting and attendance obligations","Explain work hour limits during term","Discuss Graduate Route timeline if eligible"],"performance":{"ourRate":0,"industryRate":0,"stats":[{"label":"Files this year","value":"0"},{"label":"Approved","value":"0"}]},"approvalFactors":[{"label":"Our rate vs industry","ours":89,"benchmark":76},{"label":"Financial compliance","ours":86,"benchmark":70},{"label":"CAS accuracy","ours":93,"benchmark":80},{"label":"First-submit completeness","ours":90,"benchmark":72}],"timeline":[{"weeks":"1–2","title":"Counseling, CAS review, fee agreement"},{"weeks":"2–3","title":"Funds seasoning, TB test, documents"},{"weeks":"3–4","title":"IHS payment & Irish Immigration Service Delivery submission"},{"weeks":"4–5","title":"Biometrics at VAC"},{"weeks":"3–8","title":"Irish Immigration Service Delivery processing"}],"relatedServices":[{"label":"Ireland – Graduate Route","libraryId":""},{"label":"